/* Table: ARQUIVO, Owner: SYSDBA */
CREATE TABLE ARQUIVO (ID_ARQUIVO INTEGER,
        ARQUIVO VARCHAR(30),
        EXECUTAR SMALLINT,
        CAMINHO VARCHAR(200),
        APAGAR SMALLINT,
        ID_VERSAO INTEGER,
CONSTRAINT PK_ARQUIVO PRIMARY KEY (ID_ARQUIVO));

/* Table: ATUPRC, Owner: SYSDBA */
CREATE TABLE ATUPRC (ID_ATUPRC INTEGER,
        CODUSU INTEGER,
        GRUUSU INTEGER,
        DTEATU TIMESTAMP,
        TABATU INTEGER,
        CODEMP INTEGER,
CONSTRAINT ATUPRC_PK PRIMARY KEY (ID_ATUPRC));

/* Table: CAIXA_FECHAMENTO_PDV, Owner: SYSDBA */
CREATE TABLE CAIXA_FECHAMENTO_PDV (COD_MOVIMENTO VARCHAR(9) CHARACTER SET WIN1252,
        CODIGO_EMPRESA VARCHAR(3) CHARACTER SET WIN1252,
        DATA_MOVIMENTO TIMESTAMP,
        NOME_ESTACAO VARCHAR(50) CHARACTER SET WIN1252,
        TIPO_FECHAMENTO VARCHAR(30) CHARACTER SET WIN1252,
        ENTRADAS_DINHEIRO VARCHAR(20),
        ENTRADAS_CHEQUE VARCHAR(20),
        ENTRADAS_CARTAO VARCHAR(20),
        ENTRADAS_CARTEIRA VARCHAR(20),
        ENTRADAS_OUTROS VARCHAR(20),
        RECEBIMENTO_DUPLICATA VARCHAR(20),
        SAIDAS_DINHEIRO VARCHAR(20),
        SAIDAS_CHEQUE VARCHAR(20),
        SAIDAS_CARTAO VARCHAR(20),
        SAIDAS_CARTEIRA VARCHAR(20),
        SAIDAS_OUTROS VARCHAR(20),
        VALOR_ABERTURA VARCHAR(20),
        SALDO_FINAL VARCHAR(20),
        USUARIO VARCHAR(25) CHARACTER SET WIN1252,
        HORA TIMESTAMP,
        MODO_BD VARCHAR(1) CHARACTER SET WIN1252);

/* Table: CEPBAI, Owner: SYSDBA */
CREATE TABLE CEPBAI (CODBAI VARCHAR(7),
        CODLOC VARCHAR(7),
        NOMBAI VARCHAR(60),
        ABRBAI VARCHAR(30),
        SIGUFE CHAR(2),
CONSTRAINT CEPBAI_PK PRIMARY KEY (CODBAI, CODLOC));

/* Table: CEPLOC, Owner: SYSDBA */
CREATE TABLE CEPLOC (CODLOC VARCHAR(7),
        NOMLOC VARCHAR(60),
        NCELOC CHAR(8),
        SIGUFE CHAR(2),
        TIPLOC CHAR(1),
        SITLOC CHAR(1),
        SUBLOC VARCHAR(6),
        DIRLOC CHAR(3),
        REGLOC CHAR(2),
        OPELOC CHAR(1),
CONSTRAINT CEPLOC_PK PRIMARY KEY (CODLOC));

/* Table: CEPTIT, Owner: SYSDBA */
CREATE TABLE CEPTIT (CODTIT VARCHAR(7),
        TIPTIT CHAR(1),
        NOMTIT VARCHAR(30),
        ABRTIT VARCHAR(10),
CONSTRAINT CEPTIT_PK PRIMARY KEY (CODTIT));

/* Table: CFOP, Owner: SYSDBA */
CREATE TABLE CFOP (CODCFO CHAR(5),
        DESCFO VARCHAR(1000),
        APLCFO VARCHAR(1000),
CONSTRAINT PK_CFOP PRIMARY KEY (CODCFO));

/* Table: CLIENTE_PDV, Owner: SYSDBA */
CREATE TABLE CLIENTE_PDV (CODIGO VARCHAR(6),
        NOME VARCHAR(70),
        FANTASIA VARCHAR(100),
        TIPO_PESSOA VARCHAR(8),
        CNPJ VARCHAR(18) DEFAULT '99999999999999',
        CPF VARCHAR(14) DEFAULT '11111111111',
        INSCR_ESTADUAL VARCHAR(18),
        ENDERECO VARCHAR(70),
        NUMERO VARCHAR(10),
        CIDADE VARCHAR(30),
        BAIRRO VARCHAR(25),
        CEP VARCHAR(10),
        UF VARCHAR(2),
        LIMITE_CREDITO VARCHAR(20),
        SALDO_DISPONIVEL VARCHAR(20),
        OBSERVACOES BLOB SUB_TYPE 0 SEGMENT SIZE 80,
        CODIGO_CLIENTE_COMPOSTO VARCHAR(9),
        CODIGO_EMPRESA VARCHAR(3),
        DATA_NASCIMENTO TIMESTAMP,
        TELEFONE VARCHAR(14),
        CELULAR VARCHAR(14),
        DATA_CADASTRO TIMESTAMP,
        STATUS VARCHAR(7),
        CODIGO_MUNICIPIO VARCHAR(7),
        MODO_BD VARCHAR(1));

/* Table: CMPAEN, Owner: SYSDBA */
CREATE TABLE CMPAEN (CODEMP INTEGER,
        DTEENT TIMESTAMP,
        NUMENT INTEGER,
        SEQEN2 INTEGER,
        CODEIT INTEGER,
        CODCLP CHAR(1),
        CODGRU CHAR(3),
        CODSUB CHAR(4),
        CODPRO CHAR(5),
        CODTAM VARCHAR(10),
